const now = new Date();
const runId = now.toISOString();

return [
  {
    json: {
      run_id: runId,
      run_date: runId
    }
  }
];

const runId = $('Create Run Metadata').first().json.run_id;

// -----------------------------
// 1) Read macro / Perplexity input
// -----------------------------
const inputItems = $input.all();
const rawItems = inputItems.map(item => item.json);
const rawText = JSON.stringify(rawItems, null, 2);
const lowerText = rawText.toLowerCase();

let marketPulse = "";

try {
  marketPulse = rawItems
    .map(item => {
      if (item?.choices?.[0]?.message?.content) return item.choices[0].message.content;
      if (item?.message?.content) return item.message.content;
      if (item?.content) return item.content;
      return "";
    })
    .filter(Boolean)
    .join("\n\n");
} catch (error) {
  marketPulse = "";
}

if (!marketPulse) {
  marketPulse =
    "Macro branch returned no usable market-pulse text. Treat macro overlay as incomplete for this run.";
}

// -----------------------------
// 2) Extract source URLs
// -----------------------------
let sourceUrls = [];

try {
  for (const item of rawItems) {
    if (Array.isArray(item?.citations)) {
      sourceUrls.push(...item.citations);
    }

    if (Array.isArray(item?.search_results)) {
      for (const result of item.search_results) {
        if (result?.url) sourceUrls.push(result.url);
      }
    }
  }
} catch (error) {
  sourceUrls = [];
}

sourceUrls = [...new Set(sourceUrls)].filter(Boolean);

const sourceUrlText = sourceUrls.length > 0
  ? sourceUrls.slice(0, 8).map((url, index) => `${index + 1}. ${url}`).join("\n")
  : "No macro source URLs returned.";

// -----------------------------
// 3) Read latest calculated property rows from workflow
// -----------------------------
let calculatedRows = [];

try {
  calculatedRows = $('Calculate yields').all().map(item => item.json);
} catch (error) {
  try {
    calculatedRows = $('Prepare Property Inputs').all().map(item => item.json);
  } catch (innerError) {
    calculatedRows = [];
  }
}

function isDealTest(row) {
  const sourceType = String(row.input_source_type || row.source_type || "").toLowerCase();
  return sourceType.includes("deal_test");
}

function isEvidenceSupported(row) {
  if (isDealTest(row)) return false;

  const sourceType = String(row.input_source_type || row.source_type || "").toLowerCase();
  const confidence = String(row.input_data_confidence || row.data_confidence || "").toUpperCase();

  return sourceType.includes("evidence") || confidence === "HIGH";
}

const coreRows = calculatedRows.filter(row => !isDealTest(row));
const dealTestRows = calculatedRows.filter(isDealTest);
const evidenceSupportedRows = coreRows.filter(isEvidenceSupported);
const manualRows = coreRows.filter(row => !isEvidenceSupported(row));

const coreCount = coreRows.length;
const testCount = dealTestRows.length;
const evidenceCount = evidenceSupportedRows.length;
const manualCount = manualRows.length;

const evidenceTowerNames = evidenceSupportedRows
  .map(row => row.tower)
  .filter(Boolean)
  .join(", ") || "None";

const manualTowerNames = manualRows
  .map(row => row.tower)
  .filter(Boolean)
  .join(", ") || "None";

// -----------------------------
// 4) Read bank benchmark context, if available
// -----------------------------
let bankContext = {};
try {
  bankContext = $('Create Bank Benchmark Context').first().json;
} catch (error) {
  bankContext = {};
}

const bankRate =
  bankContext?.benchmark_rate_percent !== undefined && bankContext?.benchmark_rate_percent !== null
    ? Number(bankContext.benchmark_rate_percent)
    : 3.5;

const bankQuality = bankContext?.source_quality || "MEDIUM";

const bankSourceNote =
  bankQuality === "HIGH"
    ? `Dedicated bank benchmark branch found HSBC UAE AED term-deposit evidence. ${bankRate.toFixed(2)}% is used in the property model. Source quality: HIGH.`
    : `Bank benchmark retained at ${bankRate.toFixed(2)}%. Source quality: ${bankQuality}.`;

// -----------------------------
// 5) Macro scoring rules
// -----------------------------
let financialStabilityScore = 0;
let proxyLeiScore = 0;

const hasPmiEvidence =
  lowerText.includes("pmi") ||
  lowerText.includes("s&p global") ||
  lowerText.includes("purchasing managers");

const hasExpansion =
  lowerText.includes("above 50") ||
  lowerText.includes("expansion") ||
  lowerText.includes("output growth") ||
  lowerText.includes("new business");

const hasSlowdown =
  lowerText.includes("fell") ||
  lowerText.includes("slowed") ||
  lowerText.includes("weakest") ||
  lowerText.includes("moderated") ||
  lowerText.includes("curbing demand");

const hasGeopoliticalStress =
  lowerText.includes("war") ||
  lowerText.includes("geopolitical") ||
  lowerText.includes("middle east") ||
  lowerText.includes("iran") ||
  lowerText.includes("hormuz") ||
  lowerText.includes("supply-chain") ||
  lowerText.includes("supply chain") ||
  lowerText.includes("delivery times");

const hasStrongStress =
  lowerText.includes("financial stress") ||
  lowerText.includes("external support") ||
  lowerText.includes("liquidity stress") ||
  lowerText.includes("downturn") ||
  lowerText.includes("crisis");

if (hasExpansion) proxyLeiScore += 1;
if (hasSlowdown) proxyLeiScore -= 1;
if (hasGeopoliticalStress) proxyLeiScore -= 1;

if (hasExpansion) financialStabilityScore += 1;
if (hasGeopoliticalStress) financialStabilityScore -= 1;
if (hasStrongStress) financialStabilityScore -= 1;

// Keep scores conservative and bounded
financialStabilityScore = Math.max(-3, Math.min(3, financialStabilityScore));
proxyLeiScore = Math.max(-3, Math.min(3, proxyLeiScore));

// Existing dashboard convention expects current macro to be conservative.
// If PMI expansion and stress both exist, keep financial stability neutral.
if (hasExpansion && hasGeopoliticalStress && !hasStrongStress) {
  financialStabilityScore = 0;
}

// -----------------------------
// 6) Data quality / confidence
// -----------------------------
let confidenceLevel = "LOW";
let dataQualityScore = "LOW";

if (hasPmiEvidence && sourceUrls.length > 0) {
  confidenceLevel = "MEDIUM";
  dataQualityScore = "MEDIUM";
}

if (
  hasPmiEvidence &&
  sourceUrls.some(url => String(url).toLowerCase().includes("pmi.spglobal"))
) {
  confidenceLevel = "MEDIUM";
  dataQualityScore = "MEDIUM";
}

// Property-source confidence is intentionally not upgraded here.
// Property evidence is handled separately through property_evidence_log.

// -----------------------------
// 7) Dynamic context wording
// -----------------------------
const evidenceStatusText =
  coreCount > 0
    ? `${evidenceCount}/${coreCount} core towers are evidence-supported (${evidenceTowerNames}); ${manualCount}/${coreCount} remain prototype/manual (${manualTowerNames}).`
    : "No core property rows were available in this run.";

const dealTestStatusText =
  testCount > 0
    ? `${testCount} deal-test row(s) were included and excluded from core ranking.`
    : "No active deal-test rows were included in this run.";

const propertyDataStatus =
  `Property inputs: ${evidenceStatusText} Public DLD transaction engine is not yet connected.`;

const rentalDataStatus =
  `Rental inputs: ${evidenceStatusText} Public DLD rental engine is not yet connected.`;

const macroDataStatus =
  hasPmiEvidence
    ? "Live macro context connected via Perplexity/S&P Global PMI. Source coverage depends on returned allowed-domain results."
    : "Macro branch connected, but this run did not return strong PMI evidence.";

const macroRegime =
  "Live macro context connected via Perplexity. PMI evidence is available where returned by allowed sources. Macro is used as an overlay only and does not directly override property economics.";

const riskSummary =
  `Macro context is live-connected and should be treated as an overlay. ` +
  `${evidenceStatusText} ` +
  `${dealTestStatusText} ` +
  `Do not treat manual/prototype tower outputs as investment-ready until sale/rental evidence is connected and promoted into property_inputs.`;

const scoringExplanation =
  `Current property verdict is calculated from asking price, rent, service charge, vacancy, entry/exit costs, IRR, bank spread, NPV, and quality score. ` +
  `Final Score is for ranking only: 60% yield score + 40% tower quality score. ` +
  `Hard gates remain: net yield ≥ 6.5%, IRR spread over bank ≥ +3.0%, price at or below strong-buy price, and acceptable input confidence. ` +
  `Deal-test rows are scenario checks only and are excluded from core ranking.`;

const sourceNotes =
  `Perplexity macro search results:\n${sourceUrlText}\n\n` +
  `Preferred hierarchy remains: Reuters, S&P Global PMI, DFM, Central Bank UAE, HSBC UAE, Dubai official sources, DLD transaction/rental data.`;

// -----------------------------
// 8) Output one context row
// -----------------------------
return [
  {
    json: {
      run_id: runId,

      property_rows: coreCount + testCount,

      macro_regime: macroRegime,
      market_pulse: marketPulse,

      financial_stability_score: financialStabilityScore,
      proxy_lei_score: proxyLeiScore,

      data_quality_score: dataQualityScore,
      confidence_level: confidenceLevel,

      property_data_status: propertyDataStatus,
      rental_data_status: rentalDataStatus,
      macro_data_status: macroDataStatus,

      source_notes: sourceNotes,
      risk_summary: riskSummary,
      scoring_explanation: scoringExplanation,

      dld_source_url: "https://dubailand.gov.ae",
      pmi_source_url: "https://www.pmi.spglobal.com",
      dfmgi_source_url: "https://www.dfm.ae",

      bank_source_note: bankSourceNote
    }
  }
];

const runId = $('Create Run Metadata').first().json.run_id;

// -----------------------------
// Input rows
// -----------------------------
const inputRows = $input.all().map(item => item.json);

// -----------------------------
// Bank benchmark
// -----------------------------
let bankYieldPercent = 3.5;
let bankSourceQuality = "MEDIUM";
let bankBenchmarkSourceNote = "Manual/default bank benchmark used.";

try {
  const bank = $('Create Bank Benchmark Context').first().json;

  if (bank?.benchmark_rate_percent !== undefined && bank?.benchmark_rate_percent !== null) {
    bankYieldPercent = Number(bank.benchmark_rate_percent);
  }

  bankSourceQuality = bank?.source_quality || "MEDIUM";
  bankBenchmarkSourceNote =
    `Dynamic bank benchmark used from dedicated bank branch: ${bankYieldPercent.toFixed(2)}% ${bank?.bank_name || "bank benchmark"}.`;
} catch (error) {
  bankYieldPercent = 3.5;
  bankSourceQuality = "MEDIUM";
  bankBenchmarkSourceNote = "Fallback bank benchmark used: 3.50%. Dedicated bank branch unavailable in this run.";
}

// -----------------------------
// Global assumptions
// -----------------------------
const DEFAULTS = {
  budgetMinAed: 1200000,
  budgetMaxAed: 1600000,
  vacancyPercent: 5,
  entryCostPercent: 6.6,
  exitCostPercent: 2,
  rentGrowthPercent: 2.25,
  priceGrowthPercent: 1.75,
  holdingPeriodYears: 5,
  discountRatePercent: 8,
  targetNetYieldStrongPercent: 6.5,
  targetNetYieldFairPercent: 6.0
};

// -----------------------------
// Helpers
// -----------------------------
function n(value, fallback = 0) {
  if (value === null || value === undefined || value === "") return fallback;
  const x = Number(value);
  return Number.isFinite(x) ? x : fallback;
}

function round(value, digits = 2) {
  const factor = Math.pow(10, digits);
  return Math.round(n(value) * factor) / factor;
}

function rowIsDealTest(row) {
  const sourceType = String(row.source_type || row.input_source_type || "").toLowerCase();
  return sourceType.includes("deal_test");
}

function rowIsUnvalidated(row) {
  const sourceType = String(row.source_type || row.input_source_type || "").toLowerCase();
  const confidence = String(row.data_confidence || row.input_data_confidence || "").toUpperCase();

  return (
    sourceType.includes("unvalidated") ||
    sourceType.includes("manual") ||
    sourceType.includes("prototype") ||
    confidence === "LOW"
  );
}

function hasValidFinancialInputs(row) {
  const price = n(row.asking_price_aed);
  const area = n(row.area_sqft);
  const rent = n(row.estimated_annual_rent_aed);
  const serviceCharge = n(row.service_charge_aed_sqft_year);

  return (
    price > 0 &&
    area > 0 &&
    rent > 0 &&
    serviceCharge >= 0
  );
}

function calculateIrr(cashflows) {
  let low = -0.95;
  let high = 1.0;

  function npv(rate) {
    return cashflows.reduce((sum, cf, index) => {
      return sum + cf / Math.pow(1 + rate, index);
    }, 0);
  }

  let npvLow = npv(low);
  let npvHigh = npv(high);

  let expandCount = 0;
  while (npvLow * npvHigh > 0 && expandCount < 10) {
    high += 1.0;
    npvHigh = npv(high);
    expandCount++;
  }

  if (npvLow * npvHigh > 0) return null;

  for (let i = 0; i < 100; i++) {
    const mid = (low + high) / 2;
    const npvMid = npv(mid);

    if (Math.abs(npvMid) < 0.0001) return mid * 100;

    if (npvLow * npvMid < 0) {
      high = mid;
      npvHigh = npvMid;
    } else {
      low = mid;
      npvLow = npvMid;
    }
  }

  return ((low + high) / 2) * 100;
}

function calculateNpv(cashflows, discountRatePercent) {
  const r = discountRatePercent / 100;

  return cashflows.reduce((sum, cf, index) => {
    return sum + cf / Math.pow(1 + r, index);
  }, 0);
}

function yieldScoreFromNetYield(netYieldPercent) {
  if (netYieldPercent >= 6.5) return 9.5;
  if (netYieldPercent >= 6.2) return 8.5;
  if (netYieldPercent >= 6.0) return 7.8;
  if (netYieldPercent >= 5.5) return 6.5;
  if (netYieldPercent > 0) return 5.0;
  return 0;
}

function finalDecisionFromGates(row) {
  const sourceType = String(row.input_source_type || "").toLowerCase();
  const confidence = String(row.input_data_confidence || "").toUpperCase();

  const netYield = n(row.net_yield_percent);
  const irrVsBank = n(row.irr_vs_bank_percent);
  const gapToStrongBuy = n(row.discount_to_6_5_target_aed);
  const price = n(row.asking_price_aed);

  const isDealTestRow = sourceType.includes("deal_test");

  const isUnvalidatedRow =
    sourceType.includes("unvalidated") ||
    sourceType.includes("manual") ||
    sourceType.includes("prototype");

  const isInterimEvidenceRow =
    sourceType.includes("propertyfinder_dld_derived_interim") ||
    sourceType.includes("propertyfinder") ||
    confidence === "MEDIUM-HIGH" ||
    confidence === "MEDIUM";

  const isHighEvidenceRow =
    sourceType.includes("evidence_supported") ||
    confidence === "HIGH";

  // Deal-test rows
  if (isDealTestRow) {
    return {
      finalDecision: "DEAL TEST ONLY",
      actionLabel: "Scenario check only",
      decision: "Deal test",
      decisionReason: "Deal-test row is excluded from investable ranking."
    };
  }

  // True placeholders / data gaps
  if (isUnvalidatedRow || price <= 0) {
    return {
      finalDecision: "DATA GAP",
      actionLabel: "Add trusted sale/rent evidence",
      decision: "Data gap",
      decisionReason: "Unvalidated input. Excluded from investable decision until trusted sale and rent evidence are added."
    };
  }

  // Budget cap
  if (price > DEFAULTS.budgetMaxAed) {
    return {
      finalDecision: "OUT OF BUDGET",
      actionLabel: "Monitor only",
      decision: "Out of budget",
      decisionReason: `Price is above AED ${DEFAULTS.budgetMaxAed.toLocaleString()} budget cap.`
    };
  }

  // Interim DLD-derived evidence rows
  if (isInterimEvidenceRow && !isHighEvidenceRow) {
    if (netYield >= 6.5 && irrVsBank >= 3.0 && gapToStrongBuy <= 1000) {
      return {
        finalDecision: "INTERIM BUY CANDIDATE",
        actionLabel: "Validate with direct DLD/Ejari before action",
        decision: "Interim buy candidate",
        decisionReason: "Property Finder DLD-derived evidence meets numeric gates, but still requires direct DLD/Ejari validation before investment action."
      };
    }

    if (netYield >= 6.2 && irrVsBank >= 2.5) {
      return {
        finalDecision: "INTERIM WATCH",
        actionLabel: "Watch / negotiate only if evidence improves",
        decision: "Interim watch",
        decisionReason: "Property Finder DLD-derived evidence is available, but return is below full buy gate or entry margin is insufficient."
      };
    }

    return {
      finalDecision: "INTERIM PASS",
      actionLabel: "Do not pursue at current economics",
      decision: "Interim pass",
      decisionReason: "Property Finder DLD-derived evidence is available, but net yield and/or IRR spread is below target."
    };
  }

  // High-confidence evidence rows
  if (netYield >= 6.5 && irrVsBank >= 3.0 && gapToStrongBuy <= 1000) {
    return {
      finalDecision: "BUY CANDIDATE",
      actionLabel: "Proceed to detailed due diligence",
      decision: "Buy candidate",
      decisionReason: "Evidence-supported candidate meets key numeric gates."
    };
  }

  if (netYield >= 6.2 && irrVsBank >= 2.5) {
    return {
      finalDecision: "SELECTIVE BUY",
      actionLabel: "Negotiate / selective buy",
      decision: "Watch",
      decisionReason: "Return is close to buy zone, but entry price or yield margin requires negotiation."
    };
  }

  if (netYield >= 6.0) {
    return {
      finalDecision: "WATCH",
      actionLabel: "Watch only",
      decision: "Watch",
      decisionReason: "Net yield is acceptable but below the preferred 6.2%–6.5% decision range."
    };
  }

  return {
    finalDecision: "PASS",
    actionLabel: "Do not pursue at current price",
    decision: "Pass",
    decisionReason: "Yield and/or IRR spread is below target."
  };
}

function createDataGapOutput(row) {
  const tower = row.tower || "";
  const unitType = row.unit_type || "Unknown";

  const sourceType = rowIsDealTest(row)
    ? "deal_test_input"
    : (row.source_type || row.input_source_type || "unvalidated_input");

  const confidence = rowIsDealTest(row)
    ? (row.data_confidence || row.input_data_confidence || "LOW")
    : "LOW";

  return {
    json: {
      run_id: runId,

      tower,
      unit_type: unitType,
      status: row.status || "READY",

      asking_price_aed: n(row.asking_price_aed),
      area_sqft: n(row.area_sqft),
      estimated_annual_rent_aed: n(row.estimated_annual_rent_aed),
      service_charge_aed_sqft_year: n(row.service_charge_aed_sqft_year),

      gross_yield_percent: 0,
      estimated_service_charge_aed_year: 0,
      net_rent_aed_year: 0,
      net_yield_percent: 0,

      decision: "Data gap",
      decision_reason: "Missing or unvalidated price/rent/area input. Excluded from investable decision.",
      summary: `${tower} ${unitType}: DATA GAP. Price/rent/area inputs are missing or unvalidated. Excluded from investable ranking until trusted sale and rent evidence are added.`,

      target_price_6_5_net_yield: 0,
      target_price_6_0_net_yield: 0,
      discount_to_6_5_target_aed: 0,
      discount_to_6_5_target_percent: 0,

      quality_score: n(row.quality_score),
      yield_score: 0,
      final_score: 0,

      final_decision: "DATA GAP",
      action_label: "Add trusted sale/rent evidence",

      budget_min_aed: DEFAULTS.budgetMinAed,
      budget_max_aed: DEFAULTS.budgetMaxAed,
      vacancy_percent: DEFAULTS.vacancyPercent,
      entry_cost_percent: DEFAULTS.entryCostPercent,
      exit_cost_percent: DEFAULTS.exitCostPercent,
      rent_growth_percent: DEFAULTS.rentGrowthPercent,
      price_growth_percent: DEFAULTS.priceGrowthPercent,
      holding_period_years: DEFAULTS.holdingPeriodYears,

      bank_yield_percent: bankYieldPercent,
      irr_5y_percent: 0,
      irr_vs_bank_percent: 0,
      npv_5y_aed: 0,
      discount_rate_percent: DEFAULTS.discountRatePercent,

      strong_buy_price_aed: 0,
      fair_price_aed: 0,

      input_source_type: sourceType,
      input_data_confidence: confidence,

      price_source_note: row.price_source_note || "Missing/unvalidated price. Excluded from investable decision until trusted sale evidence is added.",
      rent_source_note: row.rent_source_note || "Missing/unvalidated rent. Excluded from investable decision until trusted rental evidence is added.",
      service_charge_source_note: row.service_charge_source_note || "Service-charge source not available.",

      bank_source_quality: bankSourceQuality,
      bank_benchmark_source_note: bankBenchmarkSourceNote,

      call_script: `${tower} ${unitType}: do not discuss as investable yet. Sale/rent evidence is missing or unvalidated.`
    }
  };
}

function calculateValidOutput(row) {
  const tower = row.tower || "";
  const unitType = row.unit_type || "Unknown";

  const price = n(row.asking_price_aed);
  const area = n(row.area_sqft);
  const annualRent = n(row.estimated_annual_rent_aed);
  const serviceChargeRate = n(row.service_charge_aed_sqft_year);
  const qualityScore = n(row.quality_score);

  const vacancyFactor = 1 - DEFAULTS.vacancyPercent / 100;

  const grossYieldPercent = annualRent / price * 100;
  const serviceChargeYear = serviceChargeRate * area;
  const netRentYear = annualRent * vacancyFactor - serviceChargeYear;
  const netYieldPercent = netRentYear / price * 100;

  const targetPrice65 = netRentYear / (DEFAULTS.targetNetYieldStrongPercent / 100);
  const targetPrice60 = netRentYear / (DEFAULTS.targetNetYieldFairPercent / 100);

  const discountTo65Aed = price - targetPrice65;
  const discountTo65Percent = price > 0 ? (discountTo65Aed / price) * 100 : 0;

  const cashflows = [];
  const initialOutflow = -price * (1 + DEFAULTS.entryCostPercent / 100);
  cashflows.push(initialOutflow);

  for (let year = 1; year <= DEFAULTS.holdingPeriodYears; year++) {
    const grownRent = netRentYear * Math.pow(1 + DEFAULTS.rentGrowthPercent / 100, year - 1);
    let cashflow = grownRent;

    if (year === DEFAULTS.holdingPeriodYears) {
      const exitPrice = price * Math.pow(1 + DEFAULTS.priceGrowthPercent / 100, DEFAULTS.holdingPeriodYears);
      const exitNet = exitPrice * (1 - DEFAULTS.exitCostPercent / 100);
      cashflow += exitNet;
    }

    cashflows.push(cashflow);
  }

  const irr = calculateIrr(cashflows);
  const irr5yPercent = irr === null ? 0 : irr;
  const irrVsBankPercent = irr5yPercent - bankYieldPercent;
  const npv5yAed = calculateNpv(cashflows, DEFAULTS.discountRatePercent);

  const yieldScore = yieldScoreFromNetYield(netYieldPercent);
  const finalScore = yieldScore * 0.6 + qualityScore * 0.4;

  const preliminary = {
    input_source_type: row.source_type || row.input_source_type || "unknown",
    input_data_confidence: row.data_confidence || row.input_data_confidence || "LOW",
    net_yield_percent: netYieldPercent,
    irr_vs_bank_percent: irrVsBankPercent,
    discount_to_6_5_target_aed: discountTo65Aed,
    asking_price_aed: price
  };

  const decision = finalDecisionFromGates(preliminary);

  const requiredReductionText =
    discountTo65Aed > 1000
      ? `Needs about AED ${Math.round(discountTo65Aed).toLocaleString()} (${round(discountTo65Percent, 2)}%) price reduction to reach 6.5% net yield.`
      : `At or near the 6.5% net-yield trigger.`;

  const summary =
    `${tower} ${unitType}: Net yield is ${round(netYieldPercent, 2)}%, ` +
    `5Y IRR is ${round(irr5yPercent, 2)}%, IRR vs bank is ${round(irrVsBankPercent, 2)}%, ` +
    `quality score is ${round(qualityScore, 2)}/10, final score is ${round(finalScore, 2)}/10. ` +
    `Verdict: ${decision.finalDecision}. Action: ${decision.actionLabel}. ${requiredReductionText}`;

  const callScript =
    `I am comparing this against a ~${bankYieldPercent.toFixed(2)}% bank return. ` +
    `At current pricing, the net yield is ${round(netYieldPercent, 2)}% and estimated 5-year IRR is ${round(irr5yPercent, 2)}%. ` +
    `The deal only works if the price is supported by transaction/rental evidence and gives enough spread over the bank return.`;

  return {
    json: {
      run_id: runId,

      tower,
      unit_type: unitType,
      status: row.status || "READY",

      asking_price_aed: price,
      area_sqft: area,
      estimated_annual_rent_aed: annualRent,
      service_charge_aed_sqft_year: serviceChargeRate,

      gross_yield_percent: round(grossYieldPercent, 2),
      estimated_service_charge_aed_year: round(serviceChargeYear, 2),
      net_rent_aed_year: round(netRentYear, 2),
      net_yield_percent: round(netYieldPercent, 2),

      decision: decision.decision,
      decision_reason: decision.decisionReason,
      summary,

      target_price_6_5_net_yield: Math.round(targetPrice65),
      target_price_6_0_net_yield: Math.round(targetPrice60),
      discount_to_6_5_target_aed: Math.round(discountTo65Aed),
      discount_to_6_5_target_percent: round(discountTo65Percent, 2),

      quality_score: round(qualityScore, 2),
      yield_score: round(yieldScore, 2),
      final_score: round(finalScore, 2),

      final_decision: decision.finalDecision,
      action_label: decision.actionLabel,

      budget_min_aed: DEFAULTS.budgetMinAed,
      budget_max_aed: DEFAULTS.budgetMaxAed,
      vacancy_percent: DEFAULTS.vacancyPercent,
      entry_cost_percent: DEFAULTS.entryCostPercent,
      exit_cost_percent: DEFAULTS.exitCostPercent,
      rent_growth_percent: DEFAULTS.rentGrowthPercent,
      price_growth_percent: DEFAULTS.priceGrowthPercent,
      holding_period_years: DEFAULTS.holdingPeriodYears,

      bank_yield_percent: bankYieldPercent,
      irr_5y_percent: round(irr5yPercent, 2),
      irr_vs_bank_percent: round(irrVsBankPercent, 2),
      npv_5y_aed: Math.round(npv5yAed),
      discount_rate_percent: DEFAULTS.discountRatePercent,

      strong_buy_price_aed: Math.round(targetPrice65),
      fair_price_aed: Math.round(targetPrice60),

      input_source_type: row.source_type || row.input_source_type || "unknown",
      input_data_confidence: row.data_confidence || row.input_data_confidence || "LOW",

      price_source_note: row.price_source_note || "No price source note.",
      rent_source_note: row.rent_source_note || "No rent source note.",
      service_charge_source_note: row.service_charge_source_note || "No service-charge source note.",

      bank_source_quality: bankSourceQuality,
      bank_benchmark_source_note: bankBenchmarkSourceNote,

      call_script: callScript
    }
  };
}

// -----------------------------
// Main output
// -----------------------------
const output = [];

for (const row of inputRows) {
  const validInputs = hasValidFinancialInputs(row);
  const dealTest = rowIsDealTest(row);
  const unvalidated = rowIsUnvalidated(row);

  // Zero/null placeholder rows must not run financial math.
  if (!validInputs) {
    output.push(createDataGapOutput(row));
    continue;
  }

  // Unvalidated core rows must not run financial math even if numeric placeholders exist.
  // Deal-test rows are allowed to calculate but remain scenario checks only.
  if (unvalidated && !dealTest) {
    output.push(createDataGapOutput(row));
    continue;
  }

  output.push(calculateValidOutput(row));
}

return output;

