const runId = $('Create Run Metadata').first().json.run_id;

const response = $input.first().json;

let propertyText = "";
let searchResults = [];

if (response.choices && response.choices[0]?.message?.content) {
  propertyText = response.choices[0].message.content;
} else if (response.message?.content) {
  propertyText = response.message.content;
} else {
  propertyText = JSON.stringify(response).slice(0, 3000);
}

if (Array.isArray(response.search_results)) {
  searchResults = response.search_results;
}

const lowerText = propertyText.toLowerCase();

// Explicit negative checks
const saleNotFound =
  lowerText.includes("sale transaction evidence: not found") ||
  lowerText.includes("sale transactions: not found") ||
  lowerText.includes("sale transaction evidence is not found") ||
  lowerText.includes("sale transaction evidence not found");

const rentalNotFound =
  lowerText.includes("rental transaction evidence: not found") ||
  lowerText.includes("rental transactions: not found") ||
  lowerText.includes("rental transaction evidence is not found") ||
  lowerText.includes("rental transaction evidence not found");

const listingNotFound =
  lowerText.includes("listing evidence: not found") ||
  lowerText.includes("listings: not found") ||
  lowerText.includes("listing evidence is not found") ||
  lowerText.includes("listing evidence not found");

const officialStatsNotFound =
  lowerText.includes("official market statistics: not found") ||
  lowerText.includes("official statistics: not found") ||
  lowerText.includes("official market statistics not found");

// Positive checks only valid if not explicitly negated
const foundSaleTransactions =
  !saleNotFound &&
  (
    lowerText.includes("sale transaction evidence found") ||
    lowerText.includes("sale transactions found") ||
    lowerText.includes("transaction data found") ||
    lowerText.includes("dld transaction")
  );

const foundRentalTransactions =
  !rentalNotFound &&
  (
    lowerText.includes("rental transaction evidence found") ||
    lowerText.includes("rental transactions found") ||
    lowerText.includes("rental data found") ||
    lowerText.includes("dld rental")
  );

const foundListings =
  !listingNotFound &&
  (
    lowerText.includes("listing evidence found") ||
    lowerText.includes("listings found") ||
    lowerText.includes("active listings found")
  );

const hasDld =
  searchResults.some(r => (r.url || "").includes("dubailand.gov.ae"));

const hasTowerSpecificText =
  lowerText.includes("green lakes") ||
  lowerText.includes("madina tower") ||
  lowerText.includes("goldcrest views 2") ||
  lowerText.includes("icon tower 1") ||
  lowerText.includes("icon tower 2");

let sourceQuality = "LOW";
let confidenceLevel = "LOW";

if (hasDld && hasTowerSpecificText && (foundSaleTransactions || foundRentalTransactions)) {
  sourceQuality = "HIGH";
  confidenceLevel = "HIGH";
} else if (hasTowerSpecificText && (foundSaleTransactions || foundRentalTransactions)) {
  sourceQuality = "MEDIUM";
  confidenceLevel = "MEDIUM";
} else if (foundListings) {
  sourceQuality = "LOW-MEDIUM";
  confidenceLevel = "LOW-MEDIUM";
} else {
  sourceQuality = "LOW";
  confidenceLevel = "LOW";
}

const transactionSourceStatus = foundSaleTransactions
  ? "Potential sale transaction evidence found, requires validation."
  : "Sale transaction evidence not found in allowed sources.";

const rentalSourceStatus = foundRentalTransactions
  ? "Potential rental transaction evidence found, requires validation."
  : "Rental transaction evidence not found in allowed sources.";

const listingSourceStatus = foundListings
  ? "Potential listing evidence found, use only for negotiation context."
  : "Tower-specific listing evidence not found in allowed sources.";

const sourceUrls = searchResults
  .slice(0, 10)
  .map((r, index) => `${index + 1}. ${r.title || "Untitled"} — ${r.url || ""}`)
  .join("\n");

return [
  {
    json: {
      run_id: runId,

      source_type: "property_rental_source_check",
      tower_scope: "JLT focus towers: Green Lakes, Madina Tower, Goldcrest Views 2, Icon Tower 1, Icon Tower 2",

      source_quality: sourceQuality,
      confidence_level: confidenceLevel,

      property_search_summary: propertyText || "No property search text returned.",

      rental_search_summary: foundRentalTransactions
        ? "Rental evidence may be available in returned sources, but requires extraction and validation."
        : "Rental transaction evidence not found in allowed sources.",

      transaction_source_status: transactionSourceStatus,
      rental_source_status: rentalSourceStatus,
      listing_source_status: listingSourceStatus,

      source_notes:
        "Property-source branch is live-connected via Perplexity. Current output does not provide validated tower-level sale or rental transaction data unless explicitly stated as found. Negative statements such as 'not found' must be treated as data gaps. Static sample prices/rents must not be treated as final investment evidence.",

      source_urls: sourceUrls || "No source URLs returned."
    }
  }
];

const runId = $('Create Run Metadata').first().json.run_id;

// Read latest bank benchmark from the current run
const bankContext = $('Create Bank Benchmark Context').first().json;

const bankRateFromContext = Number(bankContext.benchmark_rate_percent);
const bankSourceQuality = bankContext.source_quality || "LOW";

const bankYieldPercent =
  bankSourceQuality === "HIGH" && !Number.isNaN(bankRateFromContext)
    ? bankRateFromContext
    : 3.5;

const bankBenchmarkSourceNote =
  bankSourceQuality === "HIGH"
    ? `Dynamic bank benchmark used from bank branch: ${bankYieldPercent}% (${bankContext.bank_name || "bank source"}).`
    : "Fallback benchmark used: 3.5%. Bank branch did not return high-quality evidence.";

const inputItems = $input.all();

const activeInputs = inputItems
  .map(item => item.json)
  .filter(row => {
    const isActive = row.is_active === true || row.is_active === "true";
    const includeInRun =
      row.include_in_run === undefined ||
      row.include_in_run === null ||
      row.include_in_run === true ||
      row.include_in_run === "true";

    return isActive && includeInRun;
  });

return activeInputs.map(row => {
  const isDealTest =
    String(row.source_type || "").toLowerCase().includes("deal_test") ||
    row.test_note !== undefined;

  return {
    json: {
      run_id: runId,

      tower: row.tower,
      unit_type: row.unit_type,
      status: row.status || "READY",

      asking_price_aed: Number(row.asking_price_aed),
      area_sqft: Number(row.area_sqft),
      estimated_annual_rent_aed: Number(row.estimated_annual_rent_aed),
      service_charge_aed_sqft_year: Number(row.service_charge_aed_sqft_year),
      quality_score: Number(row.quality_score || 6.0),

      input_source_type: isDealTest
        ? "deal_test_input"
        : (row.source_type || "manual_input"),

      input_data_confidence: row.data_confidence || "LOW",

      price_source_note: isDealTest
        ? `Deal test input. ${row.price_source_note || "Validate asking price before decision."}`
        : (row.price_source_note || ""),

      rent_source_note: isDealTest
        ? `Deal test input. ${row.rent_source_note || "Validate rent before decision."}`
        : (row.rent_source_note || ""),

      service_charge_source_note: isDealTest
        ? `Deal test input. ${row.service_charge_source_note || "Validate service charge before decision."}`
        : (row.service_charge_source_note || ""),

      test_note: row.test_note || "",

      bank_yield_percent: bankYieldPercent,
      bank_source_quality: bankSourceQuality,
      bank_benchmark_source_note: bankBenchmarkSourceNote
    }
  };
});

